// Generates the Python Blowfish demo shown on the Done step.

export function full_script(state) {
  const messageLiteral = JSON.stringify(state.bf_message ?? "hello blowfish");
  return [
    "# Blowfish — generated by cloak.moosha.org",
    "# Requires the `cryptography` package: pip install cryptography",
    "#",
    "# Blowfish is a 64-bit block Feistel cipher with variable key sizes",
    "# from 32 to 448 bits. This demo uses a 128-bit key.",
    "#",
    "# NOTE: Real systems should prefer AES for new code. Blowfish is shown",
    "# here for pedagogical reasons — its 64-bit block makes it vulnerable",
    "# to birthday attacks (SWEET32) on long-lived sessions.",
    "",
    "import os",
    "from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes",
    "from cryptography.hazmat.primitives.padding import PKCS7",
    "",
    "# Blowfish accepts keys from 4 to 56 bytes. We use 16 bytes (128 bits).",
    "key = os.urandom(16)",
    "iv = os.urandom(8)   # Blowfish block size is 64 bits = 8 bytes",
    "",
    "cipher = Cipher(algorithms.Blowfish(key), modes.CBC(iv))",
    "encryptor = cipher.encryptor()",
    "decryptor = cipher.decryptor()",
    "",
    `message = b${messageLiteral}`,
    "",
    "# PKCS#7 pad to the 8-byte (64-bit) block size — NOT 128 like AES.",
    "padder = PKCS7(64).padder()",
    "padded = padder.update(message) + padder.finalize()",
    "ciphertext = encryptor.update(padded) + encryptor.finalize()",
    "",
    "# Decrypt to confirm",
    "decrypted_padded = decryptor.update(ciphertext) + decryptor.finalize()",
    "unpadder = PKCS7(64).unpadder()",
    "decrypted = unpadder.update(decrypted_padded) + unpadder.finalize()",
    "assert decrypted == message",
    "",
    `print("key:", key.hex())`,
    `print("iv :", iv.hex())`,
    `print("ct :", ciphertext.hex())`,
    `print("decrypted:", decrypted.decode())`,
  ].join("\n");
}

